import{bQ as d,aL as e,u as a,G as r}from"./chunks/framework.D06dwy5q.js";const n=JSON.parse('{"title":"服务器上公网","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/02-服务器上公网.md","filePath":"00.互联网与架构基础/02-服务器上公网.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/02-服务器上公网.md"};function A(h,t,i,c,p,l){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="服务器上公网" tabindex="-1">服务器上公网 <a class="header-anchor" href="#服务器上公网" aria-label="Permalink to &quot;服务器上公网&quot;">​</a></h1><p>程序在一台机器上跑起来，只说明这台机器自己能执行它。外面的人能不能访问，还要看另一件事：外部网络能不能找到这台机器，找到以后能不能连到对应端口。</p><p>本机打开 <code>http://127.0.0.1:8080</code> 正常，换一台电脑就打不开，这种情况很常见。问题可能不在程序代码，而在公网 IP、路由、安全组、防火墙、端口监听、NAT 或负载均衡这些地方。</p><h2 id="一、内网和公网" tabindex="-1">一、内网和公网 <a class="header-anchor" href="#一、内网和公网" aria-label="Permalink to &quot;一、内网和公网&quot;">​</a></h2><p>服务器通常有内网地址，也可能有公网地址。</p><p>内网地址只在某个局域网、机房网络或云 VPC 里使用。公网地址能在互联网里被路由到。别人从家里的电脑、手机网络访问网站时，最终要连到某个公网入口。</p><table tabindex="0"><thead><tr><th>地址类型</th><th>常见位置</th><th>说明</th></tr></thead><tbody><tr><td>内网地址</td><td><code>10.x.x.x</code>、<code>172.16.x.x</code>、<code>192.168.x.x</code></td><td>公司内网、云 VPC、机房局域网里使用</td></tr><tr><td>公网地址</td><td>云厂商公网 IP、机房出口 IP</td><td>外部用户能通过互联网访问</td></tr></tbody></table><p>云服务器里经常看到内网 IP 和公网 IP 同时存在。内网 IP 用来和同一个 VPC 里的机器通信，公网 IP 用来接外部访问。很多云厂商的公网 IP 是一层映射，机器网卡里看到的可能仍然只有内网地址。</p><h2 id="二、公网入口" tabindex="-1">二、公网入口 <a class="header-anchor" href="#二、公网入口" aria-label="Permalink to &quot;二、公网入口&quot;">​</a></h2><p>以前在机房里，公网入口通常是运营商线路、防火墙、交换机、负载均衡设备。服务器放在内网，外部请求经过入口设备再转进来。</p><p>云上把这些东西做成了控制台里的资源：</p><table tabindex="0"><thead><tr><th>机房里的对象</th><th>云上的常见名字</th></tr></thead><tbody><tr><td>服务器</td><td>ECS、CVM、虚拟机</td></tr><tr><td>公网出口</td><td>弹性公网 IP、EIP</td></tr><tr><td>防火墙策略</td><td>安全组、网络 ACL</td></tr><tr><td>内网网段</td><td>VPC、子网</td></tr><tr><td>入口设备</td><td>负载均衡、SLB、ALB</td></tr></tbody></table><p>名字变了，事情还是那几件：外部请求先到公网入口，再经过规则检查，最后转到真正运行服务的机器或容器。</p><h2 id="三、nat" tabindex="-1">三、NAT <a class="header-anchor" href="#三、nat" aria-label="Permalink to &quot;三、NAT&quot;">​</a></h2><p>很多服务器只有内网地址，也能访问外网。比如服务器能拉镜像、装软件包、访问第三方 API，但外面的人不能直接访问它。这通常和 NAT 有关。</p><p>NAT 做地址转换。内网机器访问公网时，出口网关把内网地址换成公网地址；公网访问内网服务时，入口设备把公网地址和端口转到内网机器。</p><table tabindex="0"><thead><tr><th>NAT 类型</th><th>方向</th><th>常见场景</th></tr></thead><tbody><tr><td>SNAT</td><td>内网访问公网</td><td>服务器拉镜像、访问外部 API</td></tr><tr><td>DNAT</td><td>公网访问内网</td><td>公网 IP 的 80 端口转到内网 Web 服务</td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E5%85%AC%E7%BD%91%E7%94%A8%E6%88%B7%22%5D%0A%20%20EIP%5B%22%E5%85%AC%E7%BD%91%20IP%22%5D%0A%20%20NAT%5B%22NAT%20%2F%20%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20Server%5B%22%E5%86%85%E7%BD%91%E6%9C%8D%E5%8A%A1%E5%99%A8%2010.0.1.10%22%5D%0A%20%20App%5B%22Web%20%E6%9C%8D%E5%8A%A1%200.0.0.0%3A8080%22%5D%0A%0A%20%20User%20--%3E%20EIP%0A%20%20EIP%20--%3E%20NAT%0A%20%20NAT%20--%3E%20Server%0A%20%20Server%20--%3E%20App%0A"></div><p>一台没有公网 IP 的服务器，可能通过 SNAT 出去访问互联网。外部用户访问它时，需要 DNAT、负载均衡转发，或者给它绑定公网 IP。</p><h2 id="四、端口要放开" tabindex="-1">四、端口要放开 <a class="header-anchor" href="#四、端口要放开" aria-label="Permalink to &quot;四、端口要放开&quot;">​</a></h2><p>有公网 IP 还不够，端口也要能进来。一个 Web 服务要被访问到，至少有几处要对上。</p><table tabindex="0"><thead><tr><th>位置</th><th>要看什么</th></tr></thead><tbody><tr><td>应用进程</td><td>是否监听了正确端口，比如 <code>0.0.0.0:8080</code></td></tr><tr><td>主机防火墙</td><td>Linux 防火墙是否允许这个端口</td></tr><tr><td>云安全组</td><td>云控制台安全组是否允许外部访问</td></tr><tr><td>入口转发</td><td>负载均衡或 Nginx 是否转到正确后端</td></tr></tbody></table><p><code>127.0.0.1:8080</code> 和 <code>0.0.0.0:8080</code> 差别很大。前者只接收本机访问，后者监听所有网卡地址。服务只监听 <code>127.0.0.1</code> 时，本机 curl 正常，外部机器还是访问不到。</p><p>安全组和防火墙也容易混。安全组在云网络入口处拦，主机防火墙在操作系统里拦。安全组没放行时，请求可能到不了机器；主机防火墙拦截时，请求已经到了机器附近。</p><h2 id="五、域名指向入口" tabindex="-1">五、域名指向入口 <a class="header-anchor" href="#五、域名指向入口" aria-label="Permalink to &quot;五、域名指向入口&quot;">​</a></h2><p>真正对外提供网站时，用户通常访问域名，不直接访问 IP。域名解析到公网 IP，公网 IP 再进入服务器、负载均衡或 CDN。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20DNS%5B%22DNS%20%E8%A7%A3%E6%9E%90%22%5D%0A%20%20PublicIP%5B%22%E5%85%AC%E7%BD%91%20IP%22%5D%0A%20%20SG%5B%22%E5%AE%89%E5%85%A8%E7%BB%84%20%2F%20%E9%98%B2%E7%81%AB%E5%A2%99%22%5D%0A%20%20Nginx%5B%22Nginx%2080%2F443%22%5D%0A%20%20App%5B%22%E5%BA%94%E7%94%A8%E6%9C%8D%E5%8A%A1%208080%22%5D%0A%0A%20%20Browser%20--%3E%20DNS%0A%20%20DNS%20--%3E%20PublicIP%0A%20%20PublicIP%20--%3E%20SG%0A%20%20SG%20--%3E%20Nginx%0A%20%20Nginx%20--%3E%20App%0A"></div><p>访问不通时，可以按用户看到的现象粗略分层：</p><table tabindex="0"><thead><tr><th>用户侧现象</th><th>更接近的位置</th></tr></thead><tbody><tr><td>域名报 <code>NXDOMAIN</code></td><td>DNS 没有解析出地址</td></tr><tr><td>连接超时</td><td>公网 IP、路由、安全组、防火墙某层没回应</td></tr><tr><td>连接被拒绝</td><td>到了目标机器或入口，但端口没有服务</td></tr><tr><td>返回 <code>404</code></td><td>Web 入口可达，路径没有匹配</td></tr><tr><td>返回 <code>502</code></td><td>入口层可达，后端没有接上</td></tr></tbody></table><p>公网访问就是把“外面的人”一路带到“里面的服务”。域名、公网 IP、端口、转发规则和应用监听地址同时对上，页面才会真正打开。</p>',30)])])}const P=d(o,[["render",A]]);export{n as __pageData,P as default};
